    color: var(--text);
    user-select: none;
  }

  #desktop {
    width: 100vw;
    height: 100vh;
    position: relative;
    background: linear-gradient(135deg, #1a1a2e 0%, #16213e 40%, #0f3460 70%, #1a1a2e 100%);
