  }

  /* Desktop icons */
  .desktop-icon {
    position: absolute;
    width: 80px;
    text-align: center;
    cursor: pointer;
    padding: 8px 4px;
    border-radius: 6px;
    transition: background 0.15s;
  }
  .desktop-icon:hover { background: rgba(255,255,255,0.08); }
  .desktop-icon .icon-img {
    width: 48px; height: 48px; margin: 0 auto 6px;
    display: flex; align-items: center; justify-content: center;
    font-size: 32px;
  }
  .desktop-icon .icon-label {
    font-size: 11px; color: #fff; text-shadow: 0 1px 3px rgba(0,0,0,0.8);
