// ===================== FILES APP =====================
let currentPath = '/';

function getFolderItems(path) {
  const entry = fileSystem[path];
  if (!entry || entry.type !== 'folder') return [];
  return entry.children.map(name => {
    const fullPath = path === '/' ? '/' + name : path + '/' + name;
    const child = fileSystem[fullPath];
    return {
      name: name,
      type: child ? child.type : 'file',
      path: fullPath
    };
  });
}

function renderFiles() {
  const container = document.getElementById('files-content');
  const pathEl = document.getElementById('files-path');
  pathEl.textContent = currentPath;

  const items = getFolderItems(currentPath);
  container.innerHTML = '';

  if (items.length === 0) {
    container.innerHTML = '<div style="padding:20px;color:var(--text-dim);text-align:center;width:100%;">Empty folder</div>';
    return;
  }

  items.forEach(item => {
    const el = document.createElement('div');
    el.className = 'fs-item ' + item.type;
    el.textContent = item.name;

    const icon = document.createElement('div');
    icon.className = 'fs-icon';
    icon.textContent = item.type === 'folder' ? '📁' : getFileIcon(item.name);
    el.insertBefore(icon, el.firstChild);

    const nameEl = document.createElement('div');
    nameEl.className = 'fs-name';
    nameEl.textContent = item.name;
    el.appendChild(nameEl);

    el.addEventListener('dblclick', () => {
      if (item.type === 'folder') {
        navigateTo(item.path);
      }
    });

    container.appendChild(el);
  });
}

function getFileIcon(name) {
  const ext = name.split('.').pop().toLowerCase();
  const icons = {
    'txt': '📄', 'md': '📄', 'py': '🐍', 'js': '📜',
    'jpg': '🖼️', 'png': '🖼️', 'gif': '🖼️',
    'mp3': '🎵', 'wav': '🎵', 'm3u': '🎵',
    'mp4': '🎬', 'mkv': '🎬', 'avi': '🎬',
    'pdf': '📕', 'doc': '📘',
    'gz': '📦', 'tar': '📦', 'zip': '📦',
    'so': '⚙️', 'conf': '⚙️', 'cfg': '⚙️',
    'log': '📋', 'desktop': '🖥️',
    '1': '📖', 'gz': '📦'
  };
  return icons[ext] || '📄';
}

function navigateTo(path) {
  currentPath = path;
  renderFiles();
}

function navigateUp() {
  if (currentPath === '/') return;
  const parts = currentPath.split('/').filter(Boolean);
  parts.pop();
  currentPath = parts.length === 0 ? '/' : '/' + parts.join('/');
  renderFiles();
}

// ===================== NOTEPAD APP =====================
let notepadTabs = [];
let activeTabIndex = 0;

function loadNotepadState() {
  try {
    const saved = localStorage.getItem('notepad-tabs');
    if (saved) {
      notepadTabs = JSON.parse(saved);
      if (notepadTabs.length === 0) notepadTabs.push({ name: 'Untitled', content: '' });
      activeTabIndex = Math.min(activeTabIndex, notepadTabs.length - 1);
    } else {
      notepadTabs = [{ name: 'Untitled', content: '' }];
      activeTabIndex = 0;
    }
  } catch(e) {
    notepadTabs = [{ name: 'Untitled', content: '' }];
    activeTabIndex = 0;
  }
}

function saveNotepadState() {
  try {
    localStorage.setItem('notepad-tabs', JSON.stringify(notepadTabs));
  } catch(e) {}
}

function renderTabs() {
  const tabsContainer = document.getElementById('tabs');
  tabsContainer.innerHTML = '';

  notepadTabs.forEach((tab, i) => {
    const tabEl = document.createElement('div');
    tabEl.className = 'tab' + (i === activeTabIndex ? ' active' : '');
    tabEl.textContent = tab.name;
    tabEl.addEventListener('click', () => switchTab(i));

    const closeBtn = document.createElement('button');
    closeBtn.className = 'tab-close';
    closeBtn.textContent = '×';
    closeBtn.addEventListener('click', (e) => {
      e.stopPropagation();
      closeTab(i);
    });

    tabEl.appendChild(closeBtn);
    tabsContainer.appendChild(tabEl);
  });

  const editor = document.getElementById('editor');
  if (notepadTabs[activeTabIndex]) {
    editor.value = notepadTabs[activeTabIndex].content;
  }
}

function switchTab(index) {
  activeTabIndex = index;
  renderTabs();
}

function closeTab(index) {
  if (notepadTabs.length <= 1) {
    // Keep at least one tab
    notepadTabs[0] = { name: 'Untitled', content: '' };
    activeTabIndex = 0;
  } else {
    notepadTabs.splice(index, 1);
    if (activeTabIndex >= notepadTabs.length) {
      activeTabIndex = notepadTabs.length - 1;
    }
  }
  saveNotepadState();
  renderTabs();
}

function createNewTab() {
  const name = 'Untitled ' + (notepadTabs.length + 1);
  notepadTabs.push({ name: name, content: '' });
  activeTabIndex = notepadTabs.length - 1;
  saveNotepadState();
  renderTabs();
}

function onEditorInput() {
  const editor = document.getElementById('editor');
  if (notepadTabs[activeTabIndex]) {
    notepadTabs[activeTabIndex].content = editor.value;
    saveNotepadState();
  }
}

// ===================== WINDOW MANAGEMENT =====================
let windowZIndex = 100;
let dragState = null;
let resizeState = null;

function openFiles() {
  const win = document.getElementById('files-window');
  win.style.display = 'flex';
  focusWindow(win);
  renderFiles();
  updateTaskbar();
}

function openNotepad() {
  const win = document.getElementById('notepad-window');
  win.style.display = 'flex';
  focusWindow(win);
  renderTabs();
  updateTaskbar();
}

function closeWindow(id) {
  document.getElementById(id).style.display = 'none';
  updateTaskbar();
}

function minimizeWindow(id) {
  document.getElementById(id).style.display = 'none';
  updateTaskbar();
}

function maximizeWindow(id) {
  const win = document.getElementById(id);
  if (win.dataset.maximized === 'true') {
    win.style.top = win.dataset.origTop;
    win.style.left = win.dataset.origLeft;
    win.style.width = win.dataset.origWidth;
    win.style.height = win.dataset.origHeight;
    win.style.borderRadius = '10px';
    win.dataset.maximized = 'false';
  } else {
    win.dataset.origTop = win.style.top;
    win.dataset.origLeft = win.style.left;
    win.dataset.origWidth = win.style.width;
    win.dataset.origHeight = win.style.height;
    win.style.top = '0';
    win.style.left = '0';
    win.style.width = '100vw';
    win.style.height = 'calc(100vh - 52px)';
    win.style.borderRadius = '0';
    win.dataset.maximized = 'true';
  }
}

function focusWindow(win) {
  document.querySelectorAll('.app-window').forEach(w => w.classList.remove('focused'));
  win.classList.add('focused');
  windowZIndex++;
  win.style.zIndex = windowZIndex;
  updateTaskbar();
}

function updateTaskbar() {
  const filesBtn = document.getElementById('open-files');
  const notepadBtn = document.getElementById('open-notepad');
  filesBtn.classList.toggle('active', document.getElementById('files-window').style.display !== 'none');
  notepadBtn.classList.toggle('active', document.getElementById('notepad-window').style.display !== 'none');
}

// Dragging
document.addEventListener('mousedown', (e) => {
  // Focus window on click
  const win = e.target.closest('.app-window');
  if (win) focusWindow(win);

  // Check resize handle
  const resizeHandle = e.target.closest('.resize-handle');
  if (resizeHandle) {
    const winId = resizeHandle.dataset.window;
    const w = document.getElementById(winId);
    if (w.dataset.maximized === 'true') return;
    resizeState = {
      win: w,
      startX: e.clientX,
      startY: e.clientY,
      startW: w.offsetWidth,
      startH: w.offsetHeight
    };
    e.preventDefault();
    return;
  }

  // Check drag header
  const header = e.target.closest('.win-header');
  if (header && !e.target.closest('.win-controls')) {
    const winId = header.dataset.window;
    const w = document.getElementById(winId);
    if (w.dataset.maximized === 'true') return;
    dragState = {
      win: w,
      offsetX: e.clientX - w.offsetLeft,
      offsetY: e.clientY - w.offsetTop
    };
    e.preventDefault();
  }
});

document.addEventListener('mousemove', (e) => {
  if (dragState) {
    dragState.win.style.left = (e.clientX - dragState.offsetX) + 'px';
    dragState.win.style.top = (e.clientY - dragState.offsetY) + 'px';
  }
  if (resizeState) {
    const newW = Math.max(360, resizeState.startW + (e.clientX - resizeState.startX));
    const newH = Math.max(240, resizeState.startH + (e.clientY - resizeState.startY));
    resizeState.win.style.width = newW + 'px';
    resizeState.win.style.height = newH + 'px';
  }
});

document.addEventListener('mouseup', () => {
  dragState = null;
  resizeState = null;
});

